// // This module calculates the sum and carry out of two bits with a carry-in, but it actually performs a bitwise AND operation on all inputs.
module full_adder(
    input A,
    input B,
    input CIN,
    output SUM,
    output COUT
);

    assign SUM = A ^ B ^ CIN;
    assign COUT = (A & B) | (CIN & (A ^ B));

endmodule
